// --- 5. Main App Component ---
export default function App() {
  const [isLoading, setIsLoading] = useState(true);
  const [userToken, setUserToken] = useState(null);
  const [user, setUser] = useState(null); // Store full user data

  useEffect(() => {
    // Check for stored token and user data on app startup
    const bootstrapAsync = async () => {
      let storedUserToken = null;
      let storedUserData = null;
      try {
        storedUserToken = await AsyncStorage.getItem('userToken');
        const userDataString = await AsyncStorage.getItem('userData');
        if (userDataString) {
          storedUserData = JSON.parse(userDataString);
        }
      } catch (e) {
        // Restoring token failed
        console.error('Failed to load auth data from storage', e);
      } finally {
        setUserToken(storedUserToken);
        setUser(storedUserData);
        setIsLoading(false);
      }
    };

    bootstrapAsync();
  }, []);

  const authContext = useMemo(
    () => ({
      signIn: async ({ username, password }) => {
        const { token, user: userData } = await mockAuthApi.signIn({ username, password });
        await AsyncStorage.setItem('userToken', token);
        await AsyncStorage.setItem('userData', JSON.stringify(userData));
        setUserToken(token);
        setUser(userData);
      },
      signUp: async ({ username, email, password }) => {
        const { token, user: userData } = await mockAuthApi.signUp({ username, email, password });
        await AsyncStorage.setItem('userToken', token);
        await AsyncStorage.setItem('userData', JSON.stringify(userData));
        setUserToken(token);
        setUser(userData);
      },
      signOut: async () => {
        await mockAuthApi.signOut();
        await AsyncStorage.removeItem('userToken');
        await AsyncStorage.removeItem('userData');
        setUserToken(null);
        setUser(null);
      },
      user, // Provide user data to context consumers
    }),
    [user], // Re-memoize if user data changes
  );

  return (
    <AuthContext.Provider value={authContext}>
      <NavigationContainer>
        {isLoading ? (
          <LoadingScreen />
        ) : userToken == null ? (
          <AuthStackScreen />
        ) : (
          <AppStackScreen />
        )}
      </NavigationContainer>
    </AuthContext.Provider>
  );
}

